#define VECTOR_SIZE (32 * 1024 * 1024)

#define ELEMENTS_PER_THREAD (8)
#define FUSION_DEGREE (4)

template<class T>
inline T conv_int(const int i){ return static_cast<T>(i); }

template<class T>
inline T mad(const T a, const T b, const T c){ return a*b+c; }

template<class T>
inline bool equal(const T a, const T b){ return a==b; }

// Specializations for half2 are not needed for CPU version as we don't support half2 in standard C++ without CUDA headers
// We will simply not use half2 on CPU or map it to float if necessary, but the logic below handles types generically.
// For the CPU translation, we will skip the half2 specific benchmarks as they require CUDA specific types.
// However, to maintain structure, we'll define a placeholder or skip.
// The original code checks IsFP16Supported(). On CPU, we'll assume false.

template <class T, unsigned int granularity, unsigned int fusion_degree, unsigned int compute_iterations, bool TemperateUnroll>
void benchmark_func_cpu(T seed, T *g_data, long total_elements, long stride, long big_stride) {
    // Parallelize over the chunks defined by fusion_degree and granularity
    // The original CUDA code iterates k from 0 to fusion_degree, and j from 0 to granularity
    // idx = blockIdx.x*blockSize*granularity + threadIdx.x
    // We map this to a linear index space.

    // Total work units = (total_elements / (granularity * stride)) * fusion_degree? 
    // Actually, the CUDA code calculates idx based on grid/block.
    // Let's simulate the parallel loop over the "blocks" of data.

    long num_blocks = total_elements / (granularity * stride);
    if (num_blocks * granularity * stride > total_elements) num_blocks--; // Safety

    #pragma omp parallel for
    for (long block_idx = 0; block_idx < num_blocks; block_idx++) {
        int idx = block_idx * granularity * stride; // Simplified mapping for CPU contiguous access

        T tmps[granularity];

        for(int k=0; k<fusion_degree; k++){
            // Calculate the offset for this fusion step
            // In CUDA: idx + j*stride + k*big_stride
            // big_stride = gridDim.x * blockSize * granularity = total_elements / (blockSize * granularity) * blockSize * granularity = total_elements?
            // Actually big_stride in CUDA is the span between fusion copies.
            // For CPU, we assume the data is laid out such that we can access it.
            // The CUDA code accesses g_data[idx + j*stride + k*big_stride].
            // Since we are translating to CPU and the input is a single double array, 
            // we must ensure we don't overflow. The CUDA code allocates 'size' doubles.
            // The access pattern implies the array is treated as having multiple "layers" for fusion.
            // However, the allocation is just size*sizeof(double). 
            // In CUDA benchmark_func, big_stride = gridDim.x * blockSize * granularity.
            // gridDim.x = compute_grid_size / BLOCK_SIZE.
            // compute_grid_size = size / ELEMENTS_PER_THREAD / FUSION_DEGREE.
            // So big_stride ≈ size / FUSION_DEGREE.
            // Thus k*big_stride stays within size.

            long current_big_offset = k * big_stride;

            for(int j=0; j<granularity; j++){
                long access_idx = idx + j*stride + current_big_offset;
                if (access_idx >= total_elements) continue; // Safety check

                tmps[j] = g_data[access_idx];

                int unroll_factor = TemperateUnroll ? 4 : 128;
                // Manual unroll or just loop, compiler will handle pragmas
                for(int i=0; i<compute_iterations; i++){
                    tmps[j] = mad(tmps[j], tmps[j], seed);
                }
            }

            T sum = conv_int<T>(0);
            for(int j=0; j<granularity; j+=2) {
                if (j+1 < granularity)
                    sum = mad(tmps[j], tmps[j+1], sum);
                else
                    sum = mad(tmps[j], conv_int<T>(0), sum); // Handle odd granularity if any
            }

            if( equal(sum, conv_int<T>(-1)) ) {
                long write_idx = idx + current_big_offset;
                if (write_idx < total_elements)
                    g_data[write_idx] = sum;
            }
        }
    }
}

double get_time() {
    return omp_get_wtime();
}

void runbench_warmup(double *cd, long size){
    const long reduced_grid_size = size/(ELEMENTS_PER_THREAD)/128;
    const int BLOCK_SIZE = 256;
    const int TOTAL_REDUCED_BLOCKS = reduced_grid_size/BLOCK_SIZE;

    // Map CUDA parameters to CPU function
    // stride = BLOCK_SIZE
    // big_stride = TOTAL_REDUCED_BLOCKS * BLOCK_SIZE * ELEMENTS_PER_THREAD ? 
    // In CUDA: big_stride = gridDim.x * blockSize * granularity
    // gridDim.x = TOTAL_REDUCED_BLOCKS
    // blockSize = BLOCK_SIZE
    // granularity = ELEMENTS_PER_THREAD
    long stride = BLOCK_SIZE;
    long big_stride = (long)TOTAL_REDUCED_BLOCKS * BLOCK_SIZE * ELEMENTS_PER_THREAD;

    // Ensure big_stride doesn't exceed size roughly
    if (big_stride > size) big_stride = size / FUSION_DEGREE;

    // Run with short type, 0 iterations, true unroll
    benchmark_func_cpu< short, ELEMENTS_PER_THREAD, FUSION_DEGREE, 0, true >(
        (short)1, (short*)cd, size, stride, big_stride);
}

