template<unsigned int compute_iterations>
void runbench(double *cd, long size, bool doHalfs){
    const long compute_grid_size = size/ELEMENTS_PER_THREAD/FUSION_DEGREE;
    const int BLOCK_SIZE = 256;
    const int TOTAL_BLOCKS = compute_grid_size/BLOCK_SIZE;

    long stride = BLOCK_SIZE;
    long big_stride = (long)TOTAL_BLOCKS * BLOCK_SIZE * ELEMENTS_PER_THREAD;
    if (big_stride > size) big_stride = size / FUSION_DEGREE;

    const long long computations = (ELEMENTS_PER_THREAD*(long long)compute_grid_size+(2*ELEMENTS_PER_THREAD*compute_iterations)*(long long)compute_grid_size)*FUSION_DEGREE;
    const long long memoryoperations = size;

    double start, stop;
    float kernel_time_mad_sp = 0.0f;
    float kernel_time_mad_dp = 0.0f;
    float kernel_time_mad_hp = 0.0f;
    float kernel_time_mad_int = 0.0f;

    // Single Precision
    start = get_time();
    benchmark_func_cpu< float, ELEMENTS_PER_THREAD, FUSION_DEGREE, compute_iterations, false >(
        1.0f, (float*)cd, size, stride, big_stride);
    stop = get_time();
    kernel_time_mad_sp = (float)((stop - start) * 1000.0); // ms

    // Double Precision
    start = get_time();
    benchmark_func_cpu< double, ELEMENTS_PER_THREAD, FUSION_DEGREE, compute_iterations, false >(
        1.0, cd, size, stride, big_stride);
    stop = get_time();
    kernel_time_mad_dp = (float)((stop - start) * 1000.0); // ms

    // Half Precision - Not supported on standard CPU without specific libraries, skip or mock
    // Original code skips if doHalfs is false. On CPU, we set doHalfs to false.

    // Integer
    start = get_time();
    benchmark_func_cpu< int, ELEMENTS_PER_THREAD, FUSION_DEGREE, compute_iterations, true >(
        1, (int*)cd, size, stride, big_stride);
    stop = get_time();
    kernel_time_mad_int = (float)((stop - start) * 1000.0); // ms

    printf("         %4d,   %8.3f,%8.2f,%8.2f,%7.2f,   %8.3f,%8.2f,%8.2f,%7.2f,   %8.3f,%8.2f,%8.2f,%7.2f,  %8.3f,%8.2f,%8.2f,%7.2f\n",
        compute_iterations,
        ((double)computations)/((double)memoryoperations*sizeof(float)),
        kernel_time_mad_sp,
        ((double)computations)/kernel_time_mad_sp*1000./(double)(1000*1000*1000),
        ((double)memoryoperations*sizeof(float))/kernel_time_mad_sp*1000./(1000.*1000.*1000.),
        ((double)computations)/((double)memoryoperations*sizeof(double)),
        kernel_time_mad_dp,
        ((double)computations)/kernel_time_mad_dp*1000./(double)(1000*1000*1000),
        ((double)memoryoperations*sizeof(double))/kernel_time_mad_dp*1000./(1000.*1000.*1000.),
        ((double)2*computations)/((double)memoryoperations*sizeof(short)), // Using short as proxy for half2 size
        kernel_time_mad_hp,
        ((double)2*computations)/kernel_time_mad_hp*1000./(double)(1000*1000*1000),
        ((double)memoryoperations*sizeof(short))/kernel_time_mad_hp*1000./(1000.*1000.*1000.),
        ((double)computations)/((double)memoryoperations*sizeof(int)),
        kernel_time_mad_int,
        ((double)computations)/kernel_time_mad_int*1000./(double)(1000*1000*1000),
        ((double)memoryoperations*sizeof(int))/kernel_time_mad_int*1000./(1000.*1000.*1000.) );
}

