int main(int argc, char* argv[]) {
    printf("mixbench (%s)\n", VERSION_INFO);

    unsigned int datasize = VECTOR_SIZE * sizeof(double);

    // Simulate device info output for CPU
    printf("------------------------ Device specifications ------------------------\n");
    printf("Device:              CPU (OpenMP)\n");
